  1→/**
  2→ * Global Session Notifications
  3→ *
  4→ * Sends OS-level notifications when the app is in the background.
  5→ *
  6→ * Notification triggers:
  7→ * - Agent finished working (working → idle)                → Glass sound
  8→ * - Agent error (→ error with error_category)              → Basso sound
  9→ * - Agent needs input (→ needs_response)                   → Ping sound
 10→ * - Plan ready for review (→ needs_plan_response)          → Ping sound
 11→ * - Setup failed/completed                                 → Basso/Glass sound
 12→ *
 13→ * All transitions are detected by observing the workspace React Query cache,
 14→ * which is kept fresh by the WS subscription. No IPC event listeners needed.
 15→ *
 16→ * When the app is in the foreground, notifications are suppressed —
 17→ * Sonner toasts handle in-app feedback.
 18→ */
 19→
 20→import { useEffect, useRef } from "react";
 21→import { useQueryClient } from "@tanstack/react-query";
 22→import { match } from "ts-pattern";
 23→import { capabilities } from "@/platform/capabilities";
 24→import { sendNotification } from "@/platform/notifications";
 25→import { isWindowFocused } from "@/shared/hooks/useWindowFocus";
 26→import { track } from "@/platform/analytics";
 27→import { unreadActions } from "@/features/session/store/unreadStore";
 28→import { useWorkspaceStore } from "@/features/workspace/store";
 29→import { workspaceLayoutActions } from "@/features/workspace/store/workspaceLayoutStore";
 30→import { show as showWindow } from "@/platform/native/window";
 31→import type { SessionStatus } from "@shared/types/session";
 32→import type { RepoGroup, SetupStatus, Workspace } from "@shared/types/workspace";
 33→
 34→/**
 35→ * Batches multiple notifications within a short window into a single one.
 36→ * Prevents notification spam when multiple agents finish simultaneously.
 37→ */
 38→const BATCH_WINDOW_MS = 1500;
 39→
 40→interface FinishedEntry {
 41→  workspaceId: string;
 42→  sessionId: string;
 43→  repoName: string;
 44→  label: string;
 45→}
 46→
 47→/** Build the notification body: "repo-name · workspace-title-or-branch" */
 48→function formatBody(repoName: string, ws: Workspace): string {
 49→  const label = ws.title || ws.git_branch || ws.slug;
 50→  return `${repoName} · ${label}`;
 51→}
 52→
 53→/** Focus the app window and navigate to a specific workspace + session */
 54→function navigateToWorkspace(workspaceId: string, sessionId: string): void {
 55→  showWindow();
 56→  useWorkspaceStore.getState().selectWorkspace(workspaceId);
 57→  const layout = workspaceLayoutActions.getLayout(workspaceId);
 58→  // Activate the session's chat tab if it's not already showing
 59→  if (layout.activeChatTabSessionId !== sessionId) {
 60→    const sessionIds = layout.chatTabSessionIds.includes(sessionId)
 61→      ? layout.chatTabSessionIds
 62→      : [...layout.chatTabSessionIds, sessionId];
 63→    workspaceLayoutActions.setChatTabState(workspaceId, sessionIds, sessionId);
 64→  }
 65→}
 66→
 67→/**
 68→ * Check if the user is currently viewing a specific session.
 69→ * True when the workspace is selected AND the active chat tab matches the session.
 70→ */
 71→function checkIsViewingSession(workspaceId: string, sessionId: string): boolean {
 72→  const selectedWorkspaceId = useWorkspaceStore.getState().selectedWorkspaceId;
 73→  if (selectedWorkspaceId !== workspaceId) return false;
 74→
 75→  const layout = workspaceLayoutActions.getLayout(workspaceId);
 76→  // If no persisted active tab, the workspace's current_session_id is shown
 77→  return layout.activeChatTabSessionId === sessionId || !layout.activeChatTabSessionId;
 78→}
 79→
 80→export function useGlobalSessionNotifications() {
 81→  const prevStatusMap = useRef(new Map<string, SessionStatus>());
 82→  const prevSetupStatusMap = useRef(new Map<string, SetupStatus>());
 83→  const finishedBatch = useRef<FinishedEntry[]>([]);
 84→  const batchTimerRef = useRef<ReturnType<typeof setTimeout>>();
 85→
 86→  const queryClient = useQueryClient();
 87→
 88→  useEffect(() => {
 89→    const canNotify = capabilities.nativeNotifications;
 90→
 91→    function flushFinishedBatch() {
 92→      const batch = finishedBatch.current;
 93→      finishedBatch.current = [];
 94→      batchTimerRef.current = undefined;
 95→
 96→      if (batch.length === 0 || isWindowFocused()) return;
 97→
 98→      if (batch.length === 1) {
 99→        const entry = batch[0];
100→        sendNotification({
101→          title: "Agent finished",
102→          body: `${entry.repoName} · ${entry.label}`,
103→          sound: "Glass",
104→          onClick: () => navigateToWorkspace(entry.workspaceId, entry.sessionId),
105→        });
106→      } else {
107→        // Collect unique repo names for context
108→        const repos = [...new Set(batch.map((e) => e.repoName))];
109→        const body =
110→          repos.length === 1
111→            ? `${repos[0]} · ${batch.length} workspaces`
112→            : `${repos[0]} + ${repos.length - 1} more`;
113→        // Click navigates to the first workspace in the batch
114→        const first = batch[0];
115→        sendNotification({
116→          title: `${batch.length} agents finished`,
117→          body,
118→          sound: "Glass",
119→          onClick: () => navigateToWorkspace(first.workspaceId, first.sessionId),
120→        });
121→      }
122→    }
123→
124→    function queueFinished(entry: FinishedEntry) {
125→      finishedBatch.current.push(entry);
126→      if (!batchTimerRef.current) {
127→        batchTimerRef.current = setTimeout(flushFinishedBatch, BATCH_WINDOW_MS);
128→      }
129→    }
130→
131→    // Detect session + setup transitions from the workspace query cache.
132→    // Only watches current_session_id per workspace. Non-current sessions
133→    // (extra tabs) are handled by ChatArea which tracks workingSessionIds.
134→    const unsubscribe = queryClient.getQueryCache().subscribe((event) => {
135→      if (event.type !== "updated" || !event.query.queryKey[0]) return;
136→
137→      const key = event.query.queryKey;
138→      if (key[0] !== "workspaces" || key[1] !== "by-repo") return;
139→
140→      const groups = event.query.state.data as RepoGroup[] | undefined;
141→      if (!groups) return;
142→
143→      for (const group of groups) {
144→        for (const ws of group.workspaces) {
145→          // --- Session status transitions ---
146→          if (ws.current_session_id && ws.session_status) {
147→            const sessionId = ws.current_session_id;
148→            const status = ws.session_status as SessionStatus;
149→            const prevStatus = prevStatusMap.current.get(sessionId);
150→            prevStatusMap.current.set(sessionId, status);
151→
152→            if (prevStatus && prevStatus !== status) {
153→              // Mark session as unread when transitioning out of "working"
154→              // to any terminal state — but only if user is not currently
155→              // viewing that exact session.
156→              if (
157→                prevStatus === "working" &&
158→                (status === "idle" ||
159→                  status === "error" ||
160→                  status === "needs_response" ||
161→                  status === "needs_plan_response")
162→              ) {
163→                const isViewingSession = checkIsViewingSession(ws.id, sessionId);
164→                if (!isViewingSession) {
165→                  unreadActions.markUnread(sessionId);
166→                }
167→              }
168→
169→              // working → idle = agent finished
170→              if (prevStatus === "working" && status === "idle") {
171→                track("ai_turn_completed", { session_id: sessionId });
172→                if (canNotify && !isWindowFocused()) {
173→                  queueFinished({
174→                    workspaceId: ws.id,
175→                    sessionId,
176→                    repoName: group.repo_name,
177→                    label: ws.title || ws.git_branch || ws.slug,
178→                  });
179→                }
180→              }
181→
182→              // → needs_response = agent needs user input
183→              if (status === "needs_response" && canNotify && !isWindowFocused()) {
184→                sendNotification({
185→                  title: "Agent needs input",
186→                  body: formatBody(group.repo_name, ws),
187→                  sound: "Ping",
188→                  onClick: () => navigateToWorkspace(ws.id, sessionId),
189→                });
190→              }
191→
192→              // → needs_plan_response = plan ready for review
193→              if (status === "needs_plan_response" && canNotify && !isWindowFocused()) {
194→                sendNotification({
195→                  title: "Plan ready for review",
196→                  body: formatBody(group.repo_name, ws),
197→                  sound: "Ping",
198→                  onClick: () => navigateToWorkspace(ws.id, sessionId),
199→                });
